#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
int T,n,m;
char c[105][105];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int val(int x,int y){
    if(x&&y)return x+y;
    else return __builtin_ctz(x+y+1);
}
int main(){
    T=read();
    while(T--){
        n=read(),m=read();
        bitset<200> st;
        for(int i=0;i<n;i++)
            for(int j=0;j<m;j++){
                cin>>c[i][j];
                if(c[i][j]=='T')st.flip(val(i,j));
            }
        if(st.count())cout<<"-_-\n";
        else cout<<"=_=\n";
    }
    return 0;
}
